package analytics

import (
	"context"

	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/models"
	"socialpredict/setup"
)

// DebtRepository exposes only the user data needed for debt calculations.
type DebtRepository interface {
	ListUsers(ctx context.Context) ([]models.User, error)
}

// VolumeRepository exposes the market and bet data needed for volume calculations.
type VolumeRepository interface {
	ListMarkets(ctx context.Context) ([]models.Market, error)
	ListBetsForMarket(ctx context.Context, marketID uint) ([]models.Bet, error)
}

// FeeRepository exposes the ordered bet data needed for participation fee calculations.
type FeeRepository interface {
	ListBetsOrdered(ctx context.Context) ([]models.Bet, error)
}

// LeaderboardRepository provides the data required to compute leaderboards.
type LeaderboardRepository interface {
	DebtRepository
	VolumeRepository
}

// FinancialsRepository provides the data required for per-user financial snapshots.
type FinancialsRepository interface {
	UserMarketPositions(ctx context.Context, username string) ([]positionsmath.MarketPosition, error)
}

// DebtCalculator calculates debt-related metrics.
type DebtCalculator interface {
	Calculate(ctx context.Context, repo DebtRepository, econ *setup.EconomicConfig) (*DebtStats, error)
}

// VolumeCalculator calculates market volume metrics.
type VolumeCalculator interface {
	Calculate(ctx context.Context, repo VolumeRepository, econ *setup.EconomicConfig) (*MarketVolumeStats, error)
}

// FeeCalculator calculates betting fee metrics.
type FeeCalculator interface {
	CalculateParticipationFees(ctx context.Context, repo FeeRepository, econ *setup.EconomicConfig) (int64, error)
}

// MetricsAssembler combines calculator outputs into the final DTO.
type MetricsAssembler interface {
	Assemble(econ *setup.EconomicConfig, debt *DebtStats, volume *MarketVolumeStats, participationFees int64) *SystemMetrics
}

// MarketPositionCalculator calculates market positions for analytics consumers.
type MarketPositionCalculator interface {
	Calculate(snapshot positionsmath.MarketSnapshot, bets []models.Bet) ([]positionsmath.MarketPosition, error)
}

// Repository exposes the data access required by the analytics domain service.
type Repository interface {
	LeaderboardRepository
	FeeRepository
	FinancialsRepository
}

// Service implements analytics calculations.
type Service struct {
	repo             Repository
	econLoader       setup.EconConfigLoader
	debtCalculator   DebtCalculator
	volumeCalculator VolumeCalculator
	feeCalculator    FeeCalculator
	metricsAssembler MetricsAssembler
	positions        MarketPositionCalculator
}

// ServiceOption allows customizing analytics strategies.
type ServiceOption func(*Service)

// WithDebtCalculator overrides the default debt calculator.
func WithDebtCalculator(c DebtCalculator) ServiceOption {
	return func(s *Service) {
		if c != nil {
			s.debtCalculator = c
		}
	}
}

// WithVolumeCalculator overrides the default volume calculator.
func WithVolumeCalculator(c VolumeCalculator) ServiceOption {
	return func(s *Service) {
		if c != nil {
			s.volumeCalculator = c
		}
	}
}

// WithFeeCalculator overrides the default fee calculator.
func WithFeeCalculator(c FeeCalculator) ServiceOption {
	return func(s *Service) {
		if c != nil {
			s.feeCalculator = c
		}
	}
}

// WithMetricsAssembler overrides the default metrics assembler.
func WithMetricsAssembler(a MetricsAssembler) ServiceOption {
	return func(s *Service) {
		if a != nil {
			s.metricsAssembler = a
		}
	}
}

// WithPositionCalculator overrides the default position calculator.
func WithPositionCalculator(c MarketPositionCalculator) ServiceOption {
	return func(s *Service) {
		if c != nil {
			s.positions = c
		}
	}
}

// NewService constructs an analytics service with optional strategy overrides.
func NewService(repo Repository, econLoader setup.EconConfigLoader, opts ...ServiceOption) *Service {
	service := &Service{
		repo:       repo,
		econLoader: econLoader,
	}

	for _, opt := range opts {
		opt(service)
	}

	service.ensureStrategyDefaults()

	return service
}

func (s *Service) ensureStrategyDefaults() {
	if s.debtCalculator == nil {
		s.debtCalculator = DefaultDebtCalculator{}
	}
	if s.volumeCalculator == nil {
		s.volumeCalculator = DefaultVolumeCalculator{}
	}
	if s.feeCalculator == nil {
		s.feeCalculator = DefaultFeeCalculator{}
	}
	if s.metricsAssembler == nil {
		s.metricsAssembler = DefaultMetricsAssembler{}
	}
	if s.positions == nil {
		s.positions = defaultMarketPositionCalculator{}
	}
}

var (
	_ DebtCalculator           = DefaultDebtCalculator{}
	_ VolumeCalculator         = DefaultVolumeCalculator{}
	_ FeeCalculator            = DefaultFeeCalculator{}
	_ MetricsAssembler         = DefaultMetricsAssembler{}
	_ MarketPositionCalculator = defaultMarketPositionCalculator{}
)

package analytics

import (
	"context"
	"errors"
	"sort"

	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/models"

	"gorm.io/gorm"
)

// GormRepository implements the analytics repository interface using GORM.
type GormRepository struct {
	db                 *gorm.DB
	positionCalculator MarketPositionCalculator
}

// RepositoryOption configures the GormRepository strategies.
type RepositoryOption func(*GormRepository)

// WithRepositoryPositionCalculator overrides the default position calculator for the repository.
func WithRepositoryPositionCalculator(c MarketPositionCalculator) RepositoryOption {
	return func(r *GormRepository) {
		if c != nil {
			r.positionCalculator = c
		}
	}
}

// NewGormRepository constructs a GORM-backed analytics repository.
func NewGormRepository(db *gorm.DB, opts ...RepositoryOption) *GormRepository {
	repo := &GormRepository{
		db:                 db,
		positionCalculator: defaultMarketPositionCalculator{},
	}
	for _, opt := range opts {
		opt(repo)
	}
	return repo
}

func (r *GormRepository) WithContext(ctx context.Context) *gorm.DB {
	if r == nil || r.db == nil {
		return nil
	}
	if ctx == nil {
		return r.db
	}
	return r.db.WithContext(ctx)
}

func (r *GormRepository) dbWithContext(ctx context.Context) (*gorm.DB, error) {
	db := r.WithContext(ctx)
	if db == nil {
		return nil, errors.New("gorm repository not initialized")
	}
	return db, nil
}

func (r *GormRepository) ListUsers(ctx context.Context) ([]models.User, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var users []models.User
	if err := db.Find(&users).Error; err != nil {
		return nil, err
	}
	return users, nil
}

func (r *GormRepository) ListMarkets(ctx context.Context) ([]models.Market, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var markets []models.Market
	if err := db.Find(&markets).Error; err != nil {
		return nil, err
	}
	return markets, nil
}

func (r *GormRepository) ListBetsForMarket(ctx context.Context, marketID uint) ([]models.Bet, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var bets []models.Bet
	if err := db.
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}
	return bets, nil
}

func (r *GormRepository) ListBetsOrdered(ctx context.Context) ([]models.Bet, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var bets []models.Bet
	if err := db.
		Order("market_id ASC, placed_at ASC, id ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}
	return bets, nil
}

func (r *GormRepository) UserMarketPositions(ctx context.Context, username string) ([]positionsmath.MarketPosition, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}

	userBets, err := r.listUserBets(db, username)
	if err != nil {
		return nil, err
	}
	if len(userBets) == 0 {
		return []positionsmath.MarketPosition{}, nil
	}

	marketIDs := collectMarketIDs(userBets)

	markets, err := r.listMarketsByIDs(db, marketIDs)
	if err != nil {
		return nil, err
	}

	snapshots := buildMarketSnapshots(markets)

	allBets, err := r.listBetsByMarketIDs(db, marketIDs)
	if err != nil {
		return nil, err
	}

	betsByMarket := groupBetsByMarket(allBets)

	positions, err := r.calculateUserPositions(username, marketIDs, snapshots, betsByMarket)
	if err != nil {
		return nil, err
	}

	return positions, nil
}

func (r *GormRepository) listUserBets(db *gorm.DB, username string) ([]models.Bet, error) {
	var userBets []models.Bet
	if err := db.Where("username = ?", username).
		Order("market_id ASC, placed_at ASC, id ASC").
		Find(&userBets).Error; err != nil {
		return nil, err
	}
	return userBets, nil
}

func collectMarketIDs(bets []models.Bet) []uint {
	marketIDSet := make(map[uint]struct{}, len(bets))
	for _, bet := range bets {
		marketIDSet[bet.MarketID] = struct{}{}
	}

	marketIDs := make([]uint, 0, len(marketIDSet))
	for id := range marketIDSet {
		marketIDs = append(marketIDs, uint(id))
	}
	sort.Slice(marketIDs, func(i, j int) bool { return marketIDs[i] < marketIDs[j] })
	return marketIDs
}

func (r *GormRepository) listMarketsByIDs(db *gorm.DB, marketIDs []uint) ([]models.Market, error) {
	if len(marketIDs) == 0 {
		return []models.Market{}, nil
	}
	var markets []models.Market
	if err := db.Where("id IN ?", marketIDs).Find(&markets).Error; err != nil {
		return nil, err
	}
	return markets, nil
}

func buildMarketSnapshots(markets []models.Market) map[int64]positionsmath.MarketSnapshot {
	marketSnapshots := make(map[int64]positionsmath.MarketSnapshot, len(markets))
	for _, market := range markets {
		marketSnapshots[int64(market.ID)] = positionsmath.MarketSnapshot{
			ID:               int64(market.ID),
			CreatedAt:        market.CreatedAt,
			IsResolved:       market.IsResolved,
			ResolutionResult: market.ResolutionResult,
		}
	}
	return marketSnapshots
}

func (r *GormRepository) listBetsByMarketIDs(db *gorm.DB, marketIDs []uint) ([]models.Bet, error) {
	if len(marketIDs) == 0 {
		return []models.Bet{}, nil
	}
	var allBets []models.Bet
	if err := db.Where("market_id IN ?", marketIDs).
		Order("market_id ASC, placed_at ASC, id ASC").
		Find(&allBets).Error; err != nil {
		return nil, err
	}
	return allBets, nil
}

func groupBetsByMarket(bets []models.Bet) map[int64][]models.Bet {
	betsByMarket := make(map[int64][]models.Bet, len(bets))
	for _, bet := range bets {
		betsByMarket[int64(bet.MarketID)] = append(betsByMarket[int64(bet.MarketID)], bet)
	}
	return betsByMarket
}

func (r *GormRepository) ensurePositionCalculator() MarketPositionCalculator {
	if r.positionCalculator == nil {
		r.positionCalculator = defaultMarketPositionCalculator{}
	}
	return r.positionCalculator
}

func (r *GormRepository) calculateUserPositions(username string, marketIDs []uint, snapshots map[int64]positionsmath.MarketSnapshot, betsByMarket map[int64][]models.Bet) ([]positionsmath.MarketPosition, error) {
	calculator := r.ensurePositionCalculator()
	var positions []positionsmath.MarketPosition
	for _, marketID := range marketIDs {
		snapshot, ok := snapshots[int64(marketID)]
		if !ok {
			continue
		}

		bets := betsByMarket[int64(marketID)]
		if len(bets) == 0 {
			continue
		}

		calculated, err := calculator.Calculate(snapshot, bets)
		if err != nil {
			return nil, err
		}

		for _, pos := range calculated {
			if pos.Username == username {
				positions = append(positions, pos)
				break
			}
		}
	}

	return positions, nil
}

var (
	_ Repository            = (*GormRepository)(nil)
	_ LeaderboardRepository = (*GormRepository)(nil)
	_ FinancialsRepository  = (*GormRepository)(nil)
	_ DebtRepository        = (*GormRepository)(nil)
	_ VolumeRepository      = (*GormRepository)(nil)
	_ FeeRepository         = (*GormRepository)(nil)
)

package analytics

import (
	"context"
	"testing"
	"time"

	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/models"
	"socialpredict/models/modelstesting"
)

func leaderboardMarketDataFixture(positions []positionsmath.MarketPosition, bets []models.Bet) leaderboardMarketData {
	return leaderboardMarketData{
		positions: positions,
		bets:      bets,
	}
}

func requireLeaderboardOrder(t *testing.T, entries []GlobalUserProfitability, usernames ...string) {
	t.Helper()

	if len(entries) < len(usernames) {
		t.Fatalf("expected at least %d entries, got %d", len(usernames), len(entries))
	}
	for i, username := range usernames {
		if entries[i].Username != username {
			t.Fatalf("entry %d username = %s, want %s", i, entries[i].Username, username)
		}
	}
}

func requireGlobalLeaderboard(t *testing.T, svc *Service) []GlobalUserProfitability {
	t.Helper()

	results, err := svc.ComputeGlobalLeaderboard(context.Background())
	if err != nil {
		t.Fatalf("ComputeGlobalLeaderboard returned error: %v", err)
	}

	return results
}

func TestAggregateLeaderboardUserStats(t *testing.T) {
	markets := []leaderboardMarketData{
		leaderboardMarketDataFixture(
			[]positionsmath.MarketPosition{
				{Username: "u1", Value: 200, TotalSpent: 100, IsResolved: true},
				{Username: "u2", Value: 50, TotalSpent: 80, IsResolved: false},
			},
			nil,
		),
		leaderboardMarketDataFixture(
			[]positionsmath.MarketPosition{
				{Username: "u1", Value: 120, TotalSpent: 60, IsResolved: false},
			},
			nil,
		),
	}

	aggregates := aggregateLeaderboardUserStats(markets)

	if got := aggregates["u1"].totalProfit; got != 160 { // (200-100)+(120-60)
		t.Fatalf("u1 totalProfit = %d, want 160", got)
	}
	if got := aggregates["u1"].resolvedMarkets; got != 1 {
		t.Fatalf("u1 resolvedMarkets = %d, want 1", got)
	}
	if got := aggregates["u2"].activeMarkets; got != 1 {
		t.Fatalf("u2 activeMarkets = %d, want 1", got)
	}
}

func TestFindEarliestBetsPerUser(t *testing.T) {
	now := time.Now()
	markets := []leaderboardMarketData{
		leaderboardMarketDataFixture(
			nil,
			[]models.Bet{
				{Username: "u1", PlacedAt: now.Add(2 * time.Hour)},
				{Username: "u1", PlacedAt: now.Add(-time.Hour)},
				{Username: "u2", PlacedAt: now.Add(30 * time.Minute)},
			},
		),
	}

	aggregates := map[string]*leaderboardAggregate{
		"u1": {},
		"u2": {},
	}

	earliest := findEarliestBetsPerUser(markets, aggregates)

	if got := earliest["u1"]; !got.Equal(now.Add(-time.Hour)) {
		t.Fatalf("u1 earliest = %v, want %v", got, now.Add(-time.Hour))
	}
	if got := earliest["u2"]; !got.Equal(now.Add(30 * time.Minute)) {
		t.Fatalf("u2 earliest = %v, want %v", got, now.Add(30*time.Minute))
	}
}

func TestRankLeaderboardEntries_TieBreaksByEarliestBet(t *testing.T) {
	now := time.Now()
	entries := []GlobalUserProfitability{
		{Username: "late", TotalProfit: 100, EarliestBet: now.Add(time.Hour)},
		{Username: "early", TotalProfit: 100, EarliestBet: now},
	}

	ranked := rankLeaderboardEntries(entries)

	requireLeaderboardOrder(t, ranked, "early", "late")
	if ranked[0].Rank != 1 {
		t.Fatalf("expected early user rank 1, got %d", ranked[0].Rank)
	}
	if ranked[1].Rank != 2 {
		t.Fatalf("expected second rank to be 2, got %d", ranked[1].Rank)
	}
}

func TestComputeGlobalLeaderboard_OrdersByProfit(t *testing.T) {
	_ = modelstesting.SeedWPAMFromConfig(modelstesting.GenerateEconomicConfig())

	db := modelstesting.NewFakeDB(t)
	econ := modelstesting.GenerateEconomicConfig()

	users := []models.User{
		modelstesting.GenerateUser("alice", 0),
		modelstesting.GenerateUser("bob", 0),
	}
	for i := range users {
		if err := db.Create(&users[i]).Error; err != nil {
			t.Fatalf("create user: %v", err)
		}
	}

	market := modelstesting.GenerateMarket(1, "alice")
	market.IsResolved = true
	market.ResolutionResult = "YES"
	if err := db.Create(&market).Error; err != nil {
		t.Fatalf("create market: %v", err)
	}

	bets := []models.Bet{
		modelstesting.GenerateBet(100, "YES", "alice", uint(market.ID), 0),
		modelstesting.GenerateBet(100, "NO", "bob", uint(market.ID), time.Minute),
	}
	for _, bet := range bets {
		if err := db.Create(&bet).Error; err != nil {
			t.Fatalf("create bet: %v", err)
		}
	}

	svc := newAnalyticsService(t, db, econ)
	results := requireGlobalLeaderboard(t, svc)
	if len(results) != 2 {
		t.Fatalf("expected 2 leaderboard entries, got %d", len(results))
	}
	requireLeaderboardOrder(t, results, "alice", "bob")
	if results[0].Rank != 1 || results[1].Rank != 2 {
		t.Fatalf("expected ranks 1 and 2, got %d and %d", results[0].Rank, results[1].Rank)
	}
}

package analytics_test

import (
	"context"
	"testing"

	"socialpredict/internal/app"
	"socialpredict/internal/domain/analytics"
	dbets "socialpredict/internal/domain/bets"
	"socialpredict/models"
	"socialpredict/models/modelstesting"
	"socialpredict/setup"

	"gorm.io/gorm"
)

func newAnalyticsMetricsService(db *gorm.DB, loadEcon setup.EconConfigLoader, opts ...analytics.ServiceOption) *analytics.Service {
	repo := analytics.NewGormRepository(db)
	return analytics.NewService(repo, loadEcon, opts...)
}

func requireAnalyticsMetricInt64(t *testing.T, metric analytics.Int64Metric) int64 {
	t.Helper()
	return metric.Int64Value()
}

func requireAnalyticsSystemMetrics(t *testing.T, svc *analytics.Service) *analytics.SystemMetrics {
	t.Helper()

	metrics, err := svc.ComputeSystemMetrics(context.Background())
	if err != nil {
		t.Fatalf("compute metrics: %v", err)
	}

	return metrics
}

func TestComputeSystemMetrics_BalancedAfterFinalLockedBet(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	econConfig, loadEcon := modelstesting.UseStandardTestEconomics(t)

	users := []models.User{
		modelstesting.GenerateUser("alice", 0),
		modelstesting.GenerateUser("bob", 0),
		modelstesting.GenerateUser("carol", 0),
	}
	for i := range users {
		if err := db.Create(&users[i]).Error; err != nil {
			t.Fatalf("create user: %v", err)
		}
	}

	market := modelstesting.GenerateMarket(7001, users[0].Username)
	market.IsResolved = false
	if err := db.Create(&market).Error; err != nil {
		t.Fatalf("create market: %v", err)
	}

	creationFee := econConfig.Economics.MarketIncentives.CreateMarketCost
	if err := modelstesting.AdjustUserBalance(db, users[0].Username, -creationFee); err != nil {
		t.Fatalf("apply creation fee: %v", err)
	}

	container := app.BuildApplication(db, econConfig)
	betsService := container.GetBetsService()

	placeBet := func(username string, amount int64, outcome string) {
		if _, err := betsService.Place(context.Background(), dbets.PlaceRequest{
			Username: username,
			MarketID: uint(market.ID),
			Amount:   amount,
			Outcome:  outcome,
		}); err != nil {
			t.Fatalf("place bet for %s: %v", username, err)
		}
	}

	placeBet("alice", 10, "YES")
	placeBet("bob", 10, "NO")
	placeBet("alice", 10, "YES")
	placeBet("bob", 10, "NO")
	placeBet("carol", 30, "YES")

	svc := newAnalyticsMetricsService(db, loadEcon)
	metrics := requireAnalyticsSystemMetrics(t, svc)

	maxDebt := econConfig.Economics.User.MaximumDebtAllowed

	var usersAfter []models.User
	if err := db.Find(&usersAfter).Error; err != nil {
		t.Fatalf("load users: %v", err)
	}

	var expectedUnusedDebt int64
	for _, u := range usersAfter {
		used := int64(0)
		if u.AccountBalance < 0 {
			used = -u.AccountBalance
		}
		expectedUnusedDebt += maxDebt - used
	}

	bets, err := analytics.NewGormRepository(db).ListBetsForMarket(context.Background(), uint(market.ID))
	if err != nil {
		t.Fatalf("list bets: %v", err)
	}

	var expectedActiveVolume int64
	for _, b := range bets {
		expectedActiveVolume += b.Amount
	}

	participationFees := modelstesting.CalculateParticipationFees(econConfig, bets)
	totalUtilized := expectedUnusedDebt + expectedActiveVolume + creationFee + participationFees
	totalCapacity := maxDebt * int64(len(usersAfter))

	if got := requireAnalyticsMetricInt64(t, metrics.MoneyUtilized.ActiveBetVolume); got != expectedActiveVolume {
		t.Fatalf("active volume mismatch: want %d got %d", expectedActiveVolume, got)
	}
	if got := requireAnalyticsMetricInt64(t, metrics.MoneyUtilized.UnusedDebt); got != expectedUnusedDebt {
		t.Fatalf("unused debt mismatch: want %d got %d", expectedUnusedDebt, got)
	}
	if got := requireAnalyticsMetricInt64(t, metrics.MoneyUtilized.MarketCreationFees); got != creationFee {
		t.Fatalf("creation fee mismatch: want %d got %d", creationFee, got)
	}
	if got := requireAnalyticsMetricInt64(t, metrics.MoneyUtilized.ParticipationFees); got != participationFees {
		t.Fatalf("participation fees mismatch: want %d got %d", participationFees, got)
	}
	if got := requireAnalyticsMetricInt64(t, metrics.MoneyUtilized.TotalUtilized); got != totalUtilized {
		t.Fatalf("total utilized mismatch: want %d got %d", totalUtilized, got)
	}
	if got := requireAnalyticsMetricInt64(t, metrics.MoneyCreated.UserDebtCapacity); got != totalCapacity {
		t.Fatalf("debt capacity mismatch: want %d got %d", totalCapacity, got)
	}
	if got := requireAnalyticsMetricInt64(t, metrics.Verification.Surplus); got != 0 {
		t.Fatalf("expected zero surplus, got %d", got)
	}
}

func TestResolveMarket_DistributesAllBetVolume(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	econConfig, loadEcon := modelstesting.UseStandardTestEconomics(t)

	users := []models.User{
		modelstesting.GenerateUser("patrick", 0),
		modelstesting.GenerateUser("jimmy", 0),
		modelstesting.GenerateUser("jyron", 0),
		modelstesting.GenerateUser("testuser03", 0),
	}
	for i := range users {
		if err := db.Create(&users[i]).Error; err != nil {
			t.Fatalf("create user: %v", err)
		}
	}

	market := modelstesting.GenerateMarket(8002, users[0].Username)
	market.IsResolved = false
	if err := db.Create(&market).Error; err != nil {
		t.Fatalf("create market: %v", err)
	}

	creationFee := econConfig.Economics.MarketIncentives.CreateMarketCost
	if err := modelstesting.AdjustUserBalance(db, users[0].Username, -creationFee); err != nil {
		t.Fatalf("apply creation fee: %v", err)
	}

	container := app.BuildApplication(db, econConfig)
	betsService := container.GetBetsService()
	placeBet := func(username string, amount int64, outcome string) {
		if _, err := betsService.Place(context.Background(), dbets.PlaceRequest{
			Username: username,
			MarketID: uint(market.ID),
			Amount:   amount,
			Outcome:  outcome,
		}); err != nil {
			t.Fatalf("place bet for %s: %v", username, err)
		}
	}

	placeBet("patrick", 50, "NO")
	placeBet("jimmy", 51, "NO")
	placeBet("jimmy", 51, "NO")
	placeBet("jyron", 10, "YES")
	placeBet("testuser03", 30, "YES")

	if err := container.GetMarketsService().ResolveMarket(context.Background(), int64(market.ID), "YES", market.CreatorUsername); err != nil {
		t.Fatalf("ResolveMarket: %v", err)
	}

	repo := analytics.NewGormRepository(db)
	metricsSvc := newAnalyticsMetricsService(db, loadEcon)
	metrics := requireAnalyticsSystemMetrics(t, metricsSvc)

	if surplus := metrics.Verification.SurplusValue(); surplus != 0 {
		t.Fatalf("expected zero surplus after resolution, got %d", surplus)
	}

	// Ensure no user holds simultaneous positive YES and NO shares post-resolution
	for _, user := range users {
		positions, err := repo.UserMarketPositions(context.Background(), user.Username)
		if err != nil {
			t.Fatalf("calculate positions: %v", err)
		}
		for _, pos := range positions {
			if pos.YesSharesOwned > 0 && pos.NoSharesOwned > 0 {
				t.Fatalf("user %s holds both YES and NO shares post-resolution", user.Username)
			}
		}
	}
}

